class Solution(object):
    def shiftGrid(self, grid, k):
        m, n = len(grid), len(grid[0])
        k %= m * n
        flat = []
        for row in grid:
            flat.extend(row)
        flat = flat[-k:] + flat[:-k]
        result = []
        for i in range(m):
            result.append(flat[i*n:(i+1)*n])
        return result
